#![allow(clippy::unwrap_used, clippy::expect_used, clippy::doc_markdown)]

use mqo_eval::{
    compare::compare_files,
    types::{QuestionResult, Verdict},
};
use tempfile::NamedTempFile;

fn write_results(results: &[QuestionResult]) -> NamedTempFile {
    let f = tempfile::Builder::new()
        .suffix(".json")
        .tempfile()
        .expect("tempfile");
    serde_json::to_writer(f.as_file(), results).expect("write results");
    f
}

fn make_result(id: &str, verdict: Verdict) -> QuestionResult {
    QuestionResult {
        question: format!("Question {id}"),
        id: id.to_owned(),
        verdict,
        confidence: 0.5,
        pillars_fired: vec![],
        latency_ms: 10,
        oracle_outcome: None,
    }
}

#[test]
fn acceptance_ac5() {
    // Run A: q1=correct, q2=wrong, q3=no_bind, q4=correct
    let results_a = vec![
        make_result("q1", Verdict::Correct),
        make_result("q2", Verdict::Wrong),
        make_result("q3", Verdict::NoBind),
        make_result("q4", Verdict::Correct),
    ];
    // Run B: q1=wrong (flip!), q2=wrong (same), q3=correct (flip!), q4=correct (same)
    let results_b = vec![
        make_result("q1", Verdict::Wrong),
        make_result("q2", Verdict::Wrong),
        make_result("q3", Verdict::Correct),
        make_result("q4", Verdict::Correct),
    ];

    let file_a = write_results(&results_a);
    let file_b = write_results(&results_b);

    let flips = compare_files(
        file_a.path().to_str().unwrap(),
        file_b.path().to_str().unwrap(),
    )
    .expect("compare should succeed");

    // Exactly 2 flips.
    assert_eq!(flips.len(), 2, "expected 2 verdict flips");

    // Both verdicts must be present in each flip.
    let q1_flip = flips.iter().find(|f| f.id == "q1").expect("q1 flip must exist");
    assert_eq!(q1_flip.verdict_a, Verdict::Correct);
    assert_eq!(q1_flip.verdict_b, Verdict::Wrong);

    let q3_flip = flips.iter().find(|f| f.id == "q3").expect("q3 flip must exist");
    assert_eq!(q3_flip.verdict_a, Verdict::NoBind);
    assert_eq!(q3_flip.verdict_b, Verdict::Correct);

    // Non-flipped questions should not appear.
    assert!(flips.iter().all(|f| f.id != "q2"), "q2 same verdict should not appear");
    assert!(flips.iter().all(|f| f.id != "q4"), "q4 same verdict should not appear");
}
